                        {
                            if (i == 0)
                            {
                                string[] strArrays1 = base.Server.HtmlDecode(base.Server.HtmlEncode(strArrays[i])).Split(new char[] { '»' });
                                if (row.Table.Columns.Contains("itemtitle") && (int)strArrays1.Length >= 4)
                                {
