            }
            if (this.NetTotal != "" || this.NetAverage != "" || this.NetMaximum != "" || this.NetMinimum != "")
            {
                item2.Rows.Add(this.NetTotallbl, this.NetTotal, this.NetAverage, this.NetMaximum, this.NetMinimum);
            }
            if (this.TotalGPPercentage != "" || this.AvgGPPercentage != "" || this.MaxGPPercentage != "" || this.MinGPPercentage != "")
            {
                item2.Rows.Add("Total Gross Profit (%)", this.TotalGPPercentage, this.AvgGPPercentage, this.MaxGPPercentage, this.MinGPPercentage);
            }
            DataSet ds = new DataSet();
            DataTable dtCopy = languageConversion.Copy();
            ds.Tables.Add(dtCopy);
            ds.Tables.Add(item2);

            using (XLWorkbook wb = new XLWorkbook())
            {
                foreach (DataTable dt in ds.Tables)
                {
                    wb.Worksheets.Add(dt);
                }
                Response.Clear();
                Response.Buffer = true;
                Response.Charset = "";
                Response.ContentType = "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet";
                Response.AddHeader("content-disposition", "attachment;filename=OrderReport_Excel.xlsx");
                using (MemoryStream MyMemoryStream = new MemoryStream())
                {
                    wb.SaveAs(MyMemoryStream);
                    MyMemoryStream.WriteTo(Response.OutputStream);
                    Response.Flush();
                    Response.End();
                }
            }
        }
