        public void btnExport_vivid_OnClick(object sender, EventArgs e)
        {
            this.export = "true";
            this.Session["DeleteMsg"] = null;
            if (this.rdodetail.Checked || this.rdosummary.Checked)
            {
                string value = this.hdnInnerHtml.Value;
                string str = "OrderReport_Presentation.xls";
                base.Response.Cache.SetExpires(DateTime.Now.AddSeconds(1));
                base.Response.Clear();
                base.Response.Charset = "";
                base.Response.Cache.SetCacheability(HttpCacheability.NoCache);
                base.Response.ContentType = "application/vnd.ms-excel";
                base.Response.ContentEncoding = Encoding.Unicode;
                base.Response.BinaryWrite(Encoding.Unicode.GetPreamble());
                base.Response.AppendHeader("content-disposition", string.Concat("attachment;filename=\"", str, "\""));
                this.EnableViewState = false;
                base.Response.Write("\r\n");
                base.Response.Write(value);
                base.Response.End();
                return;
            }
            int num = 0;
            for (int i = 0; i < this.chkColumns.Items.Count; i++)
            {
                if (this.chkColumns.Items[i].Selected)
                {
                    num = 1;
                }
            }
            if (num != 1)
            {
                this.spnError.Visible = true;
                return;
            }
            DataSet orderData = this.GetOrderData(0);
            StringWriter stringWriter = new StringWriter();
            base.Response.ContentEncoding = Encoding.Unicode;
            base.Response.BinaryWrite(Encoding.Unicode.GetPreamble());
            HtmlTextWriter htmlTextWriter = new HtmlTextWriter(stringWriter);
            GridView gridView = new GridView()
            {
                DataSource = orderData
            };
            htmlTextWriter.WriteLine("<div align='left' style='width:100%;padding:10px'>");
            htmlTextWriter.WriteLine("<div align='left' style='width:100%;'>");
            htmlTextWriter.WriteLine("<div style='float:left;'>");
            htmlTextWriter.WriteLine("<span style='font-family:Arial;font-size:12px;font-weight:bold;width:70px'>Date:</span>");
            commonClass _commonClass = this.objJava;
            DateTime now = DateTime.Now;
            htmlTextWriter.WriteLine(string.Concat("<span style='font:bold 10px  Arial;color:#82858C;'>", _commonClass.Eprint_return_Date_Before_View(now.ToString(), this.CompanyID, this.UserID, false), "</span>"));
            htmlTextWriter.WriteLine("</div>");
            htmlTextWriter.WriteLine("</div>");
            htmlTextWriter.WriteLine("<br/>");
            htmlTextWriter.WriteLine("<div align='left'>");
            htmlTextWriter.WriteLine("<span style='font-size:22px;font-weight:bold;color:#BE1333;font-family:Verdana'>Order List</span>");
            htmlTextWriter.WriteLine("</div>");
            htmlTextWriter.WriteLine("<div class='only10px'></div>");
            htmlTextWriter.WriteLine("<div align='left'>");
            htmlTextWriter.WriteLine(string.Concat("<span style='font-size:20px;font-weight:300;font-family:Nina'>", this.objBase.SpecialDecode(this.CompanyName), "</span>"));
            htmlTextWriter.WriteLine("</div>");
            htmlTextWriter.WriteLine("<div style='height:20x'>&nbsp;</div>");
            htmlTextWriter.WriteLine("</div>");
            gridView.Width = Unit.Percentage(100);
            gridView.BorderWidth = 0;
            gridView.GridLines = GridLines.Both;
            gridView.HeaderStyle.Font.Bold = true;
            gridView.HeaderStyle.HorizontalAlign = HorizontalAlign.Left;
            gridView.CellPadding = 3;
            gridView.RowDataBound += new GridViewRowEventHandler(this.GridOrdReport_RowDataBound);
            gridView.DataBind();
            int num1 = 0;
            for (int j = 0; j < this.chkColumns.Items.Count; j++)
            {
                if (this.chkColumns.Items[j].Selected && (j == 0 || j == 1 || j == 2 || j == 3 || j == 4 || j == 5 || j == 6 || j == 7))
                {
                    num1++;
                }
            }
            for (int k = 0; k < gridView.Rows.Count; k++)
            {
                string text = gridView.Rows[k].Cells[0].Text;
                for (int l = k + 1; l < gridView.Rows.Count; l++)
                {
                    if (string.Compare(text, gridView.Rows[l].Cells[0].Text, true) == 0)
                    {
                        for (int m = 1; m <= num1; m++)
                        {
                            string text1 = gridView.Rows[k].Cells[m].Text;
                            string str1 = gridView.Rows[l].Cells[m].Text;
                            string.Compare(text1, str1, true);
                        }
                    }
                }
            }
            for (int n = 0; n < gridView.Rows.Count; n++)
            {
                gridView.Rows[n].Width = Unit.Percentage(20);
                gridView.Rows[n].Style.Add("border-bottom", "solid thin silver");
                gridView.Rows[n].Style.Add("color", "#000000");
                gridView.Rows[n].Style.Add("font", "10px Arial");
                gridView.Rows[n].Style.Add("height", "50px");
            }
            gridView.RenderControl(htmlTextWriter);
            htmlTextWriter.WriteLine("<table width='100%' style='border-bottom:solid thin silver'>");
            htmlTextWriter.WriteLine("<tr style='border-bottom:solid thin silver'><td>&nbsp;</td><td>&nbsp;</td></tr>");
            if (this.countexp != "")
            {
                htmlTextWriter.WriteLine("<tr >");
                htmlTextWriter.WriteLine("<td align='left'>");
                htmlTextWriter.WriteLine(string.Concat("<strong>", this.countexplbl, "</strong>"));
                htmlTextWriter.WriteLine("</td>");
                htmlTextWriter.WriteLine(string.Concat("<td align='right'>", this.countexp, "</td></tr>"));
            }
            if (this.ConvertedCount != "")
            {
                htmlTextWriter.WriteLine("<tr >");
                htmlTextWriter.WriteLine("<td align='left'>");
                htmlTextWriter.WriteLine(string.Concat("<strong>", this.ConvertedCountlbl, "</strong>"));
                htmlTextWriter.WriteLine("</td>");
                htmlTextWriter.WriteLine(string.Concat("<td align='right'>", this.ConvertedCount, "</td></tr>"));
            }
            htmlTextWriter.WriteLine("</table>");
            htmlTextWriter.WriteLine("<div style='border-bottom:solid thin silver'>");
            htmlTextWriter.WriteLine("</div>");
            htmlTextWriter.WriteLine("<table width='100%'>");
            htmlTextWriter.WriteLine("<tr style='border-bottom:solid thin silver'>");
            htmlTextWriter.WriteLine("<td align='right'>");
            htmlTextWriter.WriteLine("<strong></strong>");
            htmlTextWriter.WriteLine("</td>");
            htmlTextWriter.WriteLine("<td align='right'>");
            htmlTextWriter.WriteLine("<strong>Total</strong>");
            htmlTextWriter.WriteLine("</td>");
            htmlTextWriter.WriteLine("<td align='right'>");
            htmlTextWriter.WriteLine("<strong>Avg</strong>");
            htmlTextWriter.WriteLine("</td>");
            htmlTextWriter.WriteLine("<td align='right'>");
            htmlTextWriter.WriteLine("<strong>Max</strong>");
