        public void btnRunReport_OnClick(object sender, EventArgs e)
        {
            this.Session["DeleteMsg"] = null;
            this.btnUpdateExisting.Visible = false;
            this.btnRunReport.Visible = true;
            this.btnSaveRun.Text = "Save and Run";
            this.pnlReports.Visible = false;
            int num = 0;
            this.divtab.Visible = false;
            this.div_showfilters.Style.Add("display", "none");
            this.divusrReportsave.Style.Add("display", "none");
            this.btnfilter.Visible = true;
            this.divtoolbar.Visible = true;
            this.txt1.Visible = true;
            this.btngo.Visible = true;
            for (int i = 0; i < this.chkColumns.Items.Count; i++)
            {
                if (this.chkColumns.Items[i].Selected)
                {
                    num = 1;
                }
            }
            if (num != 1)
            {
                this.GridOrderReport.Visible = false;
                this.div_Total.Visible = false;
                this.txt1.Visible = false;
                this.btngo.Visible = false;
                this.divtoolbar.Visible = true;
                this.divAggl.Visible = false;
                return;
            }
            this.hid_runreport.Value = "RunReport";
            DataSet orderData = this.GetOrderData(1);
            DataTable dt = new DataTable();
            if (this.rdodetail.Checked || this.rdosummary.Checked)
            {
                this.GridOrderReport.Visible = false;
                this.usrPaging.Visible = false;
                this.txt1.Visible = false;
                this.btngo.Visible = false;
                this.divAggl.Visible = true;
                this.div_Total.Visible = true;
                return;
            }
            if (orderData.Tables[0].Rows.Count == 0)
            {
                this.pnlEmptyRecords.Visible = true;
                this.GridOrderReport.Visible = false;
                this.divtoolbar.Visible = true;
                this.txt1.Visible = false;
                this.btngo.Visible = false;
                this.divaggregate.Visible = false;
                this.divAggl.Visible = false;
                this.btnExport1.Visible = false;
                this.btnNewExport.Visible = false;
                return;
            }
            if (Convert.ToInt32(orderData.Tables[1].Rows[0][0].ToString()) > 100)
            {
                this.GridOrderReport.Visible = true;
                this.div_Total.Visible = true;
                this.pnlEmptyRecords.Visible = false;
                dt = SetOrderReportColumns(orderData);
                this.GridOrderReport.DataSource = dt;
                //this.GridOrderReport.RowDataBound += new GridViewRowEventHandler(this.GridOrdReport_RowDataBound);
                this.GridOrderReport.DataBind();
                //this.usrPaging.Visible = true;
                this.usrPaging.Visible = false;
                pagingreport.intCurrentPage = this.PageNumber;
                pagingreport.intPageCount = Convert.ToInt32(Math.Ceiling(Convert.ToDouble(orderData.Tables[1].Rows[0][0].ToString()) / (double)this.PageSize));
                this.usrPaging.CreatePaging();
                //this.usrPaging.OnPageChange += new PagingEventHandlerreport(this.paging_OnPageChange);
                this.CallPagingBtn_ScrollGrid(this.usrPaging);
                return;
            }
            this.txt1.Visible = false;
            this.btngo.Visible = false;
            ((LinkButton)this.usrPaging.FindControl("lnkNext")).Enabled = false;
            ((LinkButton)this.usrPaging.FindControl("lnkEnd")).Enabled = false;
            this.GridOrderReport.Visible = true;
            this.div_Total.Visible = true;
            this.pnlEmptyRecords.Visible = false;
            dt = SetOrderReportColumns(orderData);
            this.GridOrderReport.DataSource = dt;
            //this.GridOrderReport.RowDataBound += new GridViewRowEventHandler(this.GridOrdReport_RowDataBound);
            this.GridOrderReport.DataBind();
            //this.usrPaging.Visible = true;
            this.usrPaging.Visible = false;
            pagingreport.intCurrentPage = this.PageNumber;
            pagingreport.intPageCount = Convert.ToInt32(Math.Ceiling(Convert.ToDouble(orderData.Tables[1].Rows[0][0].ToString()) / (double)this.PageSize));
            this.usrPaging.CreatePaging();
            //this.usrPaging.OnPageChange += new PagingEventHandlerreport(this.paging_OnPageChange);
            this.CallPagingBtn_ScrollGrid(this.usrPaging);
        }

        protected void btnsavemultiple_onclick(object sender, EventArgs e)
        {
            string[] strArrays = this.hdn_Customers.Value.Split(new char[] { ',' });
            string[] strArrays1 = this.hdn_ReportIDs.Value.Split(new char[] { ',' });
            for (int i = 0; i < (int)strArrays1.Length; i++)
            {
                string empty = string.Empty;
                int num = 0;
                if (strArrays1[i] != "")
                {
                    string str = strArrays1[i];
                    char[] chrArray = new char[] { '\u005F' };
                    if (Convert.ToInt64(str.Split(chrArray)[0]) != (long)0)
                    {
                        string str1 = strArrays1[i];
                        char[] chrArray1 = new char[] { '\u005F' };
                        num = Convert.ToInt32(str1.Split(chrArray1)[0]);
                        empty = "C";
                    }
                    else
                    {
                        string str2 = strArrays1[i];
                        char[] chrArray2 = new char[] { '\u005F' };
                        num = Convert.ToInt32(str2.Split(chrArray2)[0]);
                        string str3 = strArrays1[i];
                        char[] chrArray3 = new char[] { '\u005F' };
                        empty = str3.Split(chrArray3)[1].ToString();
                    }
                    for (int j = 0; j < (int)strArrays.Length; j++)
                    {
                        if (strArrays[j] != "")
                        {
                            WebstoreBasePage.EstoreReports_AllocatedCustomers_Insert((long)num, Convert.ToInt64(strArrays[j]), "order", empty);
                        }
                    }
                }
            }
            this.Session["AllocatedCust_0"] = null;
            base.Response.Redirect(string.Concat(this.strSitepath, "orders/order_report.aspx"));
        }

