        private void dgGrid_ItemDataBound(object sender, DataGridItemEventArgs e)
        {
            if (e.Item.ItemType == ListItemType.Header)
            {
                for (int i = 0; i < e.Item.Controls.Count; i++)
                {
                    e.Item.Cells[0].Visible = false;
                    e.Item.Cells[i].Style.Add("border-bottom", "1px solid #BE1333");
                    if (e.Item.Cells[i].Text.ToLower() == "estimateitemid")
                    {
                        e.Item.Cells[i].Visible = false;
                        this.cellvalue_estimateitemID = i;
                    }
                    if (e.Item.Cells[i].Text.ToLower() == "itemdescription")
                    {
                        e.Item.Cells[i].Visible = false;
                        this.cellvalue_ItemDescription = i;
                    }
                    if (e.Item.Cells[i].Text.ToLower() == "clientname")
                    {
                        e.Item.Cells[i].Text = "Company";
                    }
                    if (e.Item.Cells[i].Text.ToLower() == "contactname")
                    {
                        e.Item.Cells[i].Text = "Contact Name";
                        e.Item.Cells[i].Attributes.Add("align", "left");
                    }
                    if (e.Item.Cells[i].Text.ToLower() == "department")
                    {
                        e.Item.Cells[i].Text = "Department";
                        e.Item.Cells[i].Attributes.Add("align", "left");
                    }
                    if (e.Item.Cells[i].Text.ToLower() == "customeremail")
                    {
                        e.Item.Cells[i].Text = "Customer Email";
                        e.Item.Cells[i].Attributes.Add("align", "left");
                    }
                    if (e.Item.Cells[i].Text.ToLower() == "contactemail")
                    {
                        e.Item.Cells[i].Text = "Contact Email";
                        e.Item.Cells[i].Attributes.Add("align", "left");
                    }
                    if (e.Item.Cells[i].Text.ToLower() == "contactjobtitle1")
                    {
                        e.Item.Cells[i].Text = "Contact Job Title 1";
                        e.Item.Cells[i].Attributes.Add("align", "left");
                    }
                    if (e.Item.Cells[i].Text.ToLower() == "contactjobtitle2")
                    {
                        e.Item.Cells[i].Text = "Contact Job Title 2";
                        e.Item.Cells[i].Attributes.Add("align", "left");
                    }
                    if (e.Item.Cells[i].Text.ToLower() == "contactphone")
                    {
                        e.Item.Cells[i].Text = "Contact Phone";
                        e.Item.Cells[i].Attributes.Add("align", "left");
                    }
                    if (e.Item.Cells[i].Text.ToLower() == "contactaddress")
