                        else if (this.chkColumns.Items[i].Value == "TotalExTax")
                        {
                            if (stringBuilder.ToString() == "")
                            {
                                stringBuilder.Append(" cast( SUM(   \r\nCASE      \r\nWHEN (EXISTS ( (SELECT 1 FROM tb_job WHERE JOBID = c.JOBID AND IsDeleted = 0       \r\nUNION ALL       SELECT 1 FROM tb_jobcard jc2 WHERE jc2.EstimateItemID = c.EstimateItemID AND b.isConvertedToJob = 0 AND isJobReverted = 0 )\r\n\r\n) or tp.OrderItemShipping > 0)     \r\nTHEN CASE WHEN tp.OrderItemShipping > 0 THEN ISNULL(tp.TotalSubTotal1, 0) + ISNULL(oi.OrderItemShippingCostPriceIncMarkup, 0)           \r\nELSE ISNULL(ISNULL(tp.Totalsubtotal1, 0) + ISNULL(tp.OrderItemShipping, 0), 0)       END        \r\nELSE ISNULL(ISNULL(tp.Totalsubtotal1, 0) + ISNULL(tp.OrderItemShipping, 0), 0)   END )  \r\nOVER (PARTITION BY b.EstimateID) as decimal(18,2))AS [Total Exc. Tax] ");
