                                stringBuilder.Append(" cast((CASE WHEN EXISTS ((SELECT JOBID FROM tb_job WHERE JOBID = c.JOBID AND IsDeleted = 0) UNION ALL \r\n(SELECT TOP 1 isJobReverted FROM tb_jobcard jc WHERE jc.EstimateItemID = c.EstimateItemID AND b.isConvertedToJob = 0 AND isJobReverted = 1)) \r\nTHEN (\r\nCASE WHEN ISNULL(jc.QTYNumber, 0) = 1 THEN ISNULL(tp.TotalSubTotal1, 0) \r\nWHEN ISNULL(jc.QTYNumber, 0) = 2 THEN ISNULL(tp.TotalSubTotal2, 0) \r\nWHEN ISNULL(jc.QTYNumber, 0) = 3 THEN ISNULL(tp.TotalSubTotal3, 0) \r\nWHEN ISNULL(jc.QTYNumber, 0) = 4 THEN ISNULL(tp.TotalSubTotal4, 0) ELSE ISNULL(tp.TotalSubTotal1, 0) END) \r\nELSE ISNULL(tp.TotalSubTotal1, 0) END ) as decimal(18,2)) AS [Item Ex. Tax]");
                            }
