                                stringBuilder.Append(" cast(\r\nSUM(\r\n  CASE \r\n    WHEN EXISTS (\r\n      SELECT 1 FROM tb_job WHERE JOBID = c.JOBID AND IsDeleted = 0\r\n      UNION ALL\r\n      SELECT 1 FROM tb_jobcard jc2 WHERE jc2.EstimateItemID = c.EstimateItemID AND b.isConvertedToJob = 0 AND isJobReverted = 1\r\n    )\r\n    THEN\r\n      CASE ISNULL(jc.QTYNumber, 0)\r\n        WHEN 1 THEN ISNULL(tp.TotalSubTotal1, 0)\r\n        WHEN 2 THEN ISNULL(tp.TotalSubTotal2, 0)\r\n        WHEN 3 THEN ISNULL(tp.TotalSubTotal3, 0)\r\n        WHEN 4 THEN ISNULL(tp.TotalSubTotal4, 0)\r\n        ELSE ISNULL(tp.TotalSellingPrice1, 0) \r\n      END\r\n    ELSE ISNULL(tp.TotalSubTotal1, 0) \r\n  END\r\n) OVER (PARTITION BY b.EstimateID)\r\nas decimal(18,2))AS CartCost");
