        public void GetPageBind(int PageNumber)
        {
            int num = 0;
            for (int i = 0; i < this.chkColumns.Items.Count; i++)
            {
                if (this.chkColumns.Items[i].Selected)
                {
                    num = 1;
                }
            }
            if (num != 1)
            {
                this.GridOrderReport.Visible = false;
                this.div_Total.Visible = false;
                this.divtoolbar.Visible = false;
                this.txt1.Visible = false;
                this.btngo.Visible = false;
                return;
            }
            DataSet orderData = this.GetOrderData(PageNumber);
            if (orderData.Tables[0].Rows.Count == 0)
            {
                this.pnlEmptyRecords.Visible = true;
                this.GridOrderReport.Visible = false;
                this.divtoolbar.Visible = false;
                this.txt1.Visible = false;
                this.btngo.Visible = false;
                this.btnExport1.Visible = false;
                this.btnNewExport.Visible = false;
                return;
            }
            this.GridOrderReport.Visible = true;
            this.div_Total.Visible = true;
            this.pnlEmptyRecords.Visible = false;
            DataTable dt = SetOrderReportColumns(orderData);
            this.GridOrderReport.DataSource = dt;
            //this.GridOrderReport.RowDataBound += new GridViewRowEventHandler(this.GridOrdReport_RowDataBound);
            this.GridOrderReport.DataBind();
            //this.usrPaging.Visible = true;
            this.usrPaging.Visible = false;
            pagingreport.intCurrentPage = PageNumber;
            pagingreport.intPageCount = Convert.ToInt32(Math.Ceiling(Convert.ToDouble(orderData.Tables[1].Rows[0][0].ToString()) / (double)this.PageSize));
            this.usrPaging.CreatePaging();
            //this.usrPaging.OnPageChange += new PagingEventHandlerreport(this.paging_OnPageChange);
            this.CallPagingBtn_ScrollGrid(this.usrPaging);
        }

        protected void GridOrdReport_DataBound(object sender, EventArgs e)
        {
            this.GridOrderReport.HeaderStyle.CssClass = "commonheaderstylereport1";
        }
        protected void GridOrder_OnNeedDataSource(object source, GridNeedDataSourceEventArgs e)
        {
            if (base.IsPostBack)
            {
                DataSet orderData = this.GetOrderData(this.PageNumber);
                DataTable dt = SetOrderReportColumns(orderData);
                this.GridOrderReport.DataSource = dt;
            }

        }
        protected void GridOrder_PageIndexChanged(object sender, GridPageChangedEventArgs e)
        {
            this.Session["DeleteMsg"] = null;
            this.PageNumber = e.NewPageIndex + 1;
        }

        protected void GridOrder_PageSizeChanged(object sender, GridPageSizeChangedEventArgs e)
        {
            this.Session["DeleteMsg"] = null;
            this.PageSize = e.NewPageSize;
        }
