        protected void Page_Load(object sender, EventArgs e)
        {
            string[] languageConversion;
            this.objBase.ReturnRoles_Privileges_Reports("order", "showreport", "");
            BaseClass baseClass = new BaseClass();
            string empty = string.Empty;
            if (baseClass.ReturnRoles_Privileges_ForGrid("order", "isdisplay", this.Page.Request.Url.ToString()).Trim().ToLower() == "false")
            {
                base.Response.Redirect(string.Concat(this.strSitepath, "accessdenied.aspx"));
            }
            if (this.objBase.ReturnRoles_Privileges_ReportStatus("order", "exportreport").Trim().ToLower() != "false")
            {
                this.btnExport1.Visible = true;
                this.btnNewExport.Visible = true;
            }
            else
            {
                this.btnExport1.Visible = false;
                this.btnNewExport.Visible = false;
            }
            if (this.rdosummary.Checked)
            {
                System.Web.UI.ScriptManager.RegisterStartupScript(this, base.GetType(), " ", "javascript:GetSummaryDetails();", true);
            }
            else if (this.rdodetail.Checked)
            {
                System.Web.UI.ScriptManager.RegisterStartupScript(this, base.GetType(), " ", "javascript:GetDetails();", true);
            }
            this.pg = "webstoreorder";
            if (base.Request.Params["pg"] == null)
            {
                this.pagename = "webstoreorder";
            }
            else if (base.Request.Params["pg"].ToString().Trim().ToLower() == "report")
            {
                this.pagename = "Report";
            }
            global.pageName = this.pagename;
            global.pgName = "";
            this.gloobj.setpagename(this.pagename);
            languageClass _languageClass = new languageClass();
            base.Title = _languageClass.convert(global.pageTitle("Order Report", int.Parse(this.Session["companyid"].ToString()), this.Session["companyName"].ToString()));
            if (this.pagename.ToString().ToLower().Trim() != "report")
            {
                languageConversion = new string[] { "<a href=../welcome.aspx class='subnavigator'  style='text-decoration:underline;'>", this.objLangClass.GetLanguageConversion("Home_Page_Details"), "</a>&nbsp;>&nbsp;<a href=../orders/order_view.aspx class='subnavigator'  style='text-decoration:underline;'>", this.objLangClass.GetLanguageConversion("Order_View"), "</a>" };
                base.Navigation_Path(string.Concat(languageConversion), string.Concat("&nbsp;>&nbsp;", this.objLangClass.GetLanguageConversion("Order_Report")));
            }
            else
            {
                base.Navigation_Path(string.Concat("<a href=../welcome.aspx class='subnavigator' style=text-decoration:underline>", this.objLangClass.GetLanguageConversion("Home_Page_Details"), "</a>"), string.Concat("&nbsp;>&nbsp;<a href=../common/report.aspx class='subnavigator' style=text-decoration:underline>", this.objLangClass.GetLanguageConversion("Reports"), "</a>&nbsp;>&nbsp;", this.objLangClass.GetLanguageConversion("Order_Report")));
            }
            this.CompanyID = Convert.ToInt32(this.Session["companyid"].ToString());
            this.UserID = Convert.ToInt32(this.Session["UserID"].ToString());

            if (!base.IsPostBack)
            {
                this.chkColumns.Items[16].Selected = true;
                this.chkColumns.Items[17].Selected = true;

                this.Check_SpecialPrivilege = false;
                this.Check_SpecialPrivilege = base.Check_SpecialPrivilege_For_User((long)this.UserID, (long)this.CompanyID);
                if (this.Session["CustomAccessRight"].ToString().Trim().ToLower() != "false")
                {
                    string str = string.Empty;
                    if (this.objBase.ReturnRoles_Privileges_Others("showsubtotal").ToLower() != "false")
                    {
                        this.chkColumns.Items[35].Selected = false;
                        this.chkColumns.Items[35].Enabled = true;
                        this.chkExcTax.Items[0].Enabled = true;
                        this.chkExcTax.Items[0].Selected = true;
                    }
                    else
                    {
                        this.chkColumns.Items[35].Enabled = false;
                        this.chkColumns.Items[35].Selected = false;
                        this.chkExcTax.Items[0].Enabled = false;
                        this.chkExcTax.Items[0].Selected = false;
